import requests
import json

BASE_URL = 'http://localhost:8080'
auth_header = {'Authorization': 'Bearer <clinician_token>'}

payload = {
  'resourceType': 'Observation',
  'status': 'final',
  'code': {
    'coding': [
      {
        'system': 'http://loinc.org',
        'code': '2345-7',
        'display': 'Glucose'
      }
    ]
  },
  'subject': {'reference': 'Patient/patient-123'},
  'effectiveDateTime': '2024-01-15T10:30:00Z'
}

resp = requests.post(
    f'{BASE_URL}/Observation',
    json=payload,
    headers=auth_header
)

assert resp.status_code == 201, f'Expected 201, got {resp.status_code}'
body = resp.json()
assert 'id' in body, 'Response missing observation ID'
assert body['code']['coding'][0]['code'] == '2345-7'
assert body['subject']['reference'] == 'Patient/patient-123'

